Single.Single:
// 🛑 1. GATE AUTOMATE
IF NOT Enable THEN
    Ready := FALSE;
    SafeStop := TRUE;             // Sécurité par défaut : arrêt forcé
    SafetyOk := FALSE;
    RETURN;
END_IF;

Ready := TRUE;

// 🔑 2. RESET DÉFAUTS
IF Reset AND Error THEN
    Error := FALSE;
    ErrorId := 16#0000;
END_IF;

// 🛡️ 3. LOGIQUE FAIL-SAFE (Perte de signal = Danger)
IF NOT EStopArmed THEN
    ErrorId := 16#0001;           // Code : Arrêt d'urgence activé
ELSIF NOT CanOnline OR NOT CanOperational THEN
    ErrorId := 16#0002;           // Code : Liaison Joystick perdue
ELSIF NOT EthercatOk THEN
    ErrorId := 16#0004;           // Code : Bus EtherCAT en faute
END_IF;

// 📤 4. ARBITRAGE DES SORTIES TRANSVERSES
Error := (ErrorId <> 16#0000);

// SafeStop est l'actionneur logiciel (TRUE = On coupe tout)
SafeStop := Error;

// SafetyOk est le feu vert (TRUE = Tout est sain)
SafetyOk := NOT Error;
